arguments.argument:
if global.gamePaused=false
{
  if myProg=0
  {
    if delayTime>0 {delayTime-=1}
    else
    {
      visible=1
      image_xscale+=0.04; image_yscale+=0.04
      if image_xscale>=1
      {
        bCanDealDamage=1
        bCanTakeDamage=1
        myProg=1
      }
    }
  }
  else if myProg=1
  {
    scaleWave+=pi/50
    image_xscale=0.85+(sin(scaleWave)/4)
    image_yscale=0.85+(sin(scaleWave)/4)
  }
  enemyStepEvent()
}
